            `l${(this.iconSize * -0.1).toFixed(1)},${(this.iconSize * 0.1).toFixed(1)} q${(this.iconSize * 0.2).toFixed(1)},${(this.iconSize * 0.28).toFixed(1)} ${(this.iconSize * 0.48).toFixed(1)},${(this.iconSize * 0.48).toFixed(1)} ` +
