// DataStore.ets — single source of truth (observable + persisted).
import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import {
  HazardItem, HazardProgress, PatrolRoute, PatrolCheckpoint, CheckinRecord,
  ContactItem, ContactGroup, SafetyTodo, HazardForm, RiskLevel, HazardStatus,
} from '../model/Types';
import { STATUS_LABEL } from '../common/Theme';

const PREF_NAME = 'pinankou_store';
const PREF_KEY = 'state';

function uid(prefix: string): string {
  return `${prefix}_${Date.now().toString(36)}_${Math.floor(Math.random() * 1e6).toString(36)}`;
}

function defaultRoutes(): PatrolRoute[] {
  const mk = (id: string, name: string, description: string, names: string[]): PatrolRoute => {
    const cps: PatrolCheckpoint[] = names.map((n, i) => ({
      id: `${id}-cp${i + 1}`, routeId: id, name: n, order: i + 1,
    }));
    return { id, name, description, checkpoints: cps };
  };
  return [
    mk('route-a', '厂区A线日间巡检', '主车间 + 仓储区', ['配电室', '主车间A', '危化品仓库', '消防通道', '门卫室']),
    mk('route-b', '罐区夜间巡检', '储罐区及装卸站台', ['1号储罐', '装卸站台', '防溢围堰', '应急物资柜']),
  ];
}

@Observed
export class DataStore {
  hazards: HazardItem[] = [];
  routes: PatrolRoute[] = [];
  patrolRecords: CheckinRecord[] = [];
  contacts: ContactItem[] = [];
  todosSeed: SafetyTodo[] = [];

  // patrol session
  activeRouteId: string = '';
  checkedCheckpoints: string[] = [];

  // profile
  profileName: string = '安全员';
  profileRole: 'user' | 'admin' = 'user';

  private ctx: common.Context | null = null;
  private seeded: boolean = false;

  attachContext(context: common.Context): void {
    this.ctx = context;
  }

  async load(context: common.Context): Promise<void> {
    this.ctx = context;
    try {
      const pref = await preferences.getPreferences(context, PREF_NAME);
      const raw = await pref.get(PREF_KEY, '') as string;
      if (raw && raw.length > 0) {
        const obj: Record<string, Object> = JSON.parse(raw);
        this.hazards = (obj['hazards'] as HazardItem[]) ?? [];
        this.routes = (obj['routes'] as PatrolRoute[]) ?? [];
        this.patrolRecords = (obj['patrolRecords'] as CheckinRecord[]) ?? [];
        this.contacts = (obj['contacts'] as ContactItem[]) ?? [];
        this.profileName = (obj['profileName'] as string) ?? '安全员';
        this.profileRole = (obj['profileRole'] === 'admin') ? 'admin' : 'user';
        this.seeded = true;
      }
    } catch (e) {
      // keep defaults
    }
    this.seedRoutesIfEmpty();
  }

  private async persist(): Promise<void> {
    if (!this.ctx) {
      return;
    }
    try {
      const pref = await preferences.getPreferences(this.ctx, PREF_NAME);
      const payload: Record<string, Object> = {
        'hazards': this.hazards,
        'routes': this.routes,
        'patrolRecords': this.patrolRecords,
        'contacts': this.contacts,
        'profileName': this.profileName,
        'profileRole': this.profileRole,
      };
      await pref.put(PREF_KEY, JSON.stringify(payload));
      await pref.flush();
    } catch (e) {
      // best-effort
    }
  }

  seedRoutesIfEmpty(): void {
