  private checkin(cpId: string, abnormal: boolean): void {
    this.store.checkinCheckpoint(cpId, abnormal, abnormal ? '现场发现异常' : '');
    if (abnormal) {
      promptAction.showToast({ message: '异常已记录，请同步上报隐患' });
    } else {
      promptAction.showToast({ message: '打卡成功' });
    }
  }
}

