// Theme.ets — 平安扣 Pinankou
// Blue-green safety palette. Semantic token names are preserved so scaffold
// shell components (BottomTabBar, SvgIcon) keep compiling.
export class Theme {
  // Backgrounds
  static readonly pageBg: string = '#EEF5F6';
  static readonly cardBg: string = '#FFFFFF';
  static readonly softSurfaceBg: string = '#F4F9FA';
  static readonly overlayBg: string = 'rgba(10,55,60,0.45)';

  // Brand — teal/green safety
  static readonly brandPrimary: string = '#0E7C86';
  static readonly brandDeep: string = '#0A4F57';
  static readonly brandSoft: string = '#E3F1F2';
  static readonly brandAccent: string = '#1E88E5'; // support blue
  static readonly brandGradientStart: string = '#0E7C86';
  static readonly brandGradientEnd: string = '#0A4F57';

  // Risk / status colors
  static readonly riskLow: string = '#2E9B6B';
  static readonly riskLowBg: string = '#E6F5EE';
  static readonly riskMedium: string = '#E0A100';
  static readonly riskMediumBg: string = '#FBF1D9';
  static readonly riskHigh: string = '#EF6C00';
  static readonly riskHighBg: string = '#FCEBDB';
  static readonly riskCritical: string = '#D32F2F';
  static readonly riskCriticalBg: string = '#FBE3E3';

  // Text
  static readonly textPrimary: string = '#10303A';
  static readonly textSecondary: string = 'rgba(16,48,58,0.78)';
  static readonly textTertiary: string = 'rgba(16,48,58,0.56)';
